// Types
export interface InventoryItem {
  id: string;
  name: string;
  available: number;
  reserved: number;
}

export interface ReservationToken {
  id: string;
  itemId: string;
  quantity: number;
}

// Main class
export class InventoryReservationSystem {
  private inventory: Map<string, InventoryItem>;
  private reservations: Map<string, ReservationToken>;
  private nextReservationId: number;

  constructor() {
    this.inventory = new Map();
    this.reservations = new Map();
    this.nextReservationId = 0;
  }

  // Add item to inventory
  addItem(id: string, name: string, quantity: number): void {
    if (this.inventory.has(id)) {
      throw new Error(`Item ${id} already exists`);
    }
    this.inventory.set(id, {
      id,
      name,
      available: quantity,
      reserved: 0,
    });
  }

  // Reserve stock
  reserve(itemId: string, quantity: number): ReservationToken {
    const item = this.inventory.get(itemId);
    if (!item) {
      throw new Error(`Item ${itemId} not found`);
    }
    if (item.available < quantity) {
      throw new Error(`Insufficient stock for item ${itemId}`);
    }

    const reservationId = `res_${this.nextReservationId++}`;
    const token: ReservationToken = { id: reservationId, itemId, quantity };
    item.available -= quantity;
    item.reserved += quantity;
    this.reservations.set(reservationId, token);
    return token;
  }

  // Release a reservation
  release(reservationId: string): void {
    const token = this.reservations.get(reservationId);
    if (!token) {
      throw new Error(`Reservation ${reservationId} not found`);
    }

    const item = this.inventory.get(token.itemId);
    if (item) {
      item.available += token.quantity;
      item.reserved -= token.quantity;
    }
    this.reservations.delete(reservationId);
  }

  // Check availability
  checkAvailability(itemId: string, quantity: number): boolean {
    const item = this.inventory.get(itemId);
    return item ? item.available >= quantity : false;
  }

  // Get item details
  getItem(itemId: string): InventoryItem | undefined {
    return this.inventory.get(itemId);
  }
}
