  getInventoryStatus(itemId: string): InventoryItem | null {
    const item = this.inventory.get(itemId);
    return item ? { ...item } : null;
  }

  getAllInventory(): InventoryItem[] {
    return Array.from(this.inventory.values()).map((item) => ({ ...item }));
